INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Single Sign-On$q$, $q$Users authenticate once to access thousands of pre-integrated apps from the gallery, plus custom-registered applications, without repeated logins.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Multi-Factor Authentication$q$, $q$Adds a second verification step via app notification, phone, or hardware key to reduce the risk of compromised passwords.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Conditional Access$q$, $q$Policy engine that grants, blocks, or challenges sign-ins based on user, device, location, and application risk signals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Identity Protection$q$, $q$Detects risky sign-ins and compromised accounts using behavioral and threat intelligence signals, then triggers automated remediation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Privileged Identity Management$q$, $q$Grants just-in-time, time-bound elevation to administrative roles instead of standing privileged access.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Self-Service Password Reset$q$, $q$Lets end users reset or unlock their own accounts through verified methods, cutting help-desk password tickets.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Hybrid Identity$q$, $q$Synchronizes on-premises Active Directory identities to the cloud so users have one consistent identity across environments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$B2B and B2C Collaboration$q$, $q$Extends secure, governed access to external partners and customer-facing applications outside the core organization.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Access Reviews$q$, $q$Lets managers and resource owners periodically recertify group membership, app access, and role assignments.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Application Proxy$q$, $q$Publishes on-premises web applications for secure remote access with conditional access protection, without a VPN.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Deep, native integration with Microsoft 365, Windows, and Azure for organizations already in that ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Broad application gallery with thousands of pre-built single sign-on integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Granular conditional access policies allow precise, risk-based control over sign-ins$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Scales from small teams on the free tier to large enterprises with complex governance needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Strong hybrid identity support for organizations still running on-premises Active Directory$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Advanced security and governance features require premium P1 or P2 licensing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Conditional access and role configuration has a real learning curve for new administrators$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Best experience is tied to the Microsoft ecosystem, less compelling for non-Microsoft stacks$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Licensing structure across Microsoft 365 and Entra ID plans can be confusing to navigate$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Initial tenant setup and policy design can take significant planning time to get right$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Is Microsoft Entra ID the same as Azure Active Directory?$q$, $q$Yes, Microsoft renamed Azure Active Directory to Microsoft Entra ID, keeping the same underlying service and directory while consolidating it under the broader Microsoft Entra identity product family.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Does Microsoft Entra ID have a free plan?$q$, $q$Yes, a free tier is included with directory services and basic reporting, and it's also bundled at no extra cost with many Microsoft 365 and Azure subscriptions.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Can Microsoft Entra ID work with non-Microsoft applications?$q$, $q$Yes, it supports standard protocols like SAML, OpenID Connect, and OAuth, and includes an application gallery with pre-built connectors for many popular third-party SaaS tools.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$What's the difference between Entra ID P1 and P2?$q$, $q$P1 adds conditional access, hybrid identity, and self-service password reset, while P2 layers on Identity Protection's risk-based detection and Privileged Identity Management for just-in-time admin access.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Do I need on-premises Active Directory to use Microsoft Entra ID?$q$, $q$No, Entra ID works as a standalone cloud directory, but it can also synchronize with an existing on-premises Active Directory for organizations running a hybrid identity setup.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Enterprise Single Sign-On$q$, $q$Centralize authentication across Microsoft 365, Azure, and third-party SaaS apps so employees sign in once per session.$q$, $q$IT administrators at mid-size to large enterprises$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Securing Remote and Hybrid Work$q$, $q$Apply conditional access and multi-factor authentication so access depends on device health, location, and risk level rather than network location alone.$q$, $q$Security teams supporting distributed workforces$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Partner and Customer Access$q$, $q$Extend governed, secure access to external collaborators or customer-facing applications through B2B and B2C identity features.$q$, $q$Organizations collaborating with external partners or building customer-facing apps$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Privileged Access Governance$q$, $q$Replace standing administrative privileges with time-bound, approval-based elevation and periodic access recertification.$q$, $q$Compliance and security teams in regulated industries$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Cloud directory for users and groups","Basic single sign-on to select apps","Self-service password change","Basic security reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Microsoft Entra ID P1$q$, $q$$6/user/month$q$, $q$monthly$q$, $q$["Conditional access policies","Hybrid identity with on-premises AD","Self-service password reset with writeback","Group-based access management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Microsoft Entra ID P2$q$, $q$$9/user/month$q$, $q$monthly$q$, $q$["Everything in P1","Identity Protection risk-based detection","Privileged Identity Management","Access reviews and entitlement management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Entra ID, formerly known as Azure Active Directory, is Microsoft's cloud-based identity and access management service. It authenticates users and secures access to internal resources, such as apps on a corporate network or intranet, and external resources, such as Microsoft 365, the Azure portal, and thousands of other SaaS applications. It underpins single sign-on for organizations already invested in the Microsoft ecosystem.$q$, $q$At its core, Entra ID centralizes identity: employees, contractors, and partners each get a managed identity that follows them across devices and applications. Administrators define who can access what through group membership, conditional access policies, and role assignments, replacing scattered credentials and ad hoc access lists with a single governed directory that can be audited and reported on.$q$, $q$Because it is deeply woven into Windows, Microsoft 365, and Azure, Entra ID is often the default identity layer for organizations that already run those products, though it also supports hybrid setups with on-premises Active Directory and integrates with non-Microsoft applications through standard protocols like SAML and OpenID Connect.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$who-microsoft-entra-id-is-for$q$, $q$Who Microsoft Entra ID Is For$q$, 2, ARRAY[$q$Entra ID is built for IT and security teams at organizations of any size that need centralized control over who can sign in and what they can reach once they do. Companies already using Microsoft 365, Windows endpoints, or Azure infrastructure gain the most immediate value, since Entra ID is the identity backbone those products expect.$q$, $q$It also suits organizations with hybrid environments that need to bridge an existing on-premises Active Directory with cloud applications, using synchronization tools to keep identities consistent across both worlds. Enterprises with compliance obligations benefit from its conditional access, access reviews, and privileged identity management capabilities for demonstrating least-privilege access.$q$, $q$Managed service providers and IT consultancies that administer identity for multiple client tenants also rely on Entra ID, as do developers building multi-tenant SaaS applications who need a mature identity platform to handle authentication rather than building it themselves.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small teams or solo operators with a handful of lightweight cloud tools may find Entra ID more infrastructure than they need. Its concepts, tenants, conditional access, app registrations, and directory roles carry a learning curve that can feel disproportionate for a team that just wants simple shared logins.$q$, $q$Organizations fully committed to a non-Microsoft stack, for example running entirely on Google Workspace or an open-source identity provider, may prefer an identity platform more natively aligned with that ecosystem, since some of Entra ID's deepest conveniences, like seamless Windows sign-on, are tied to Microsoft products.$q$, $q$Teams with strict budget constraints who need advanced features like risk-based conditional access, identity protection, or privileged access management should also weigh the cost carefully, since the more powerful capabilities sit behind paid premium tiers rather than the free offering.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Single sign-on lets users authenticate once and access thousands of pre-integrated applications from the app gallery without re-entering credentials, reducing password fatigue and help-desk tickets tied to forgotten logins. Multi-factor authentication adds a second verification step, and conditional access policies let administrators require it only in specific risk contexts, such as unfamiliar locations or unmanaged devices.$q$, $q$Identity Protection uses risk signals to flag suspicious sign-ins and compromised credentials, while Privileged Identity Management allows just-in-time, time-bound elevation of administrative roles instead of leaving accounts permanently privileged. Access reviews let managers periodically recertify who still needs access to a resource, and self-service password reset reduces administrative overhead for end users.$q$, $q$Hybrid identity features connect on-premises Active Directory to the cloud directory, and B2B and B2C capabilities extend secure access to external partners and customers. Application proxy and secure hybrid access extend conditional access protections to legacy on-premises applications without requiring a VPN.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$the-microsoft-entra-id-experience$q$, $q$The Microsoft Entra ID Experience$q$, 2, ARRAY[$q$Administrators manage Entra ID primarily through the Microsoft Entra admin center, a web console for configuring users, groups, applications, and policies, alongside PowerShell and Microsoft Graph API access for scripting and automation at scale. The interface groups settings by function, identity governance, protection, and applications, which helps once the underlying concepts are familiar.$q$, $q$End users mostly experience Entra ID indirectly, through the familiar Microsoft sign-in screen, occasional multi-factor prompts, and the My Apps portal where they can launch assigned applications from one place. When configured well, sign-in feels seamless, particularly on managed Windows devices where authentication happens automatically in the background.$q$, $q$The initial setup and policy design require real planning, since conditional access rules and role assignments can be complex to get right, but Microsoft provides templates, deployment guidance, and a security score to help administrators harden their tenant progressively rather than all at once.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('71439181-0154-4626-9efe-059864fd8420', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
