INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Drag-and-drop form builder$q$, $q$Build surveys, quizzes, and polls quickly with a simple visual editor and no coding required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Quiz mode with auto-grading$q$, $q$Set correct answers and point values so responses are scored automatically, ideal for classroom assessments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Branching logic$q$, $q$Show or hide questions based on prior answers to create more personalized, adaptive forms (Microsoft 365).$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Real-time results dashboard$q$, $q$View response summaries and auto-generated charts as answers come in, without manual setup.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Excel export$q$, $q$Send collected responses straight into Excel for further analysis, pivoting, or reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Microsoft Teams integration$q$, $q$Share forms and run polls directly inside Teams chats, channels, and meetings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Customizable themes$q$, $q$Apply color themes and background images to give forms a more branded look and feel.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$File upload questions$q$, $q$Let respondents attach files as part of their answers, stored securely to the associated Microsoft account.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Co-authoring and sharing controls$q$, $q$Collaborate with colleagues on the same form and control who inside or outside the organization can respond.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Multiple distribution options$q$, $q$Share forms via direct link, QR code, embedded webpage, or email invitation.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Free to use with any Microsoft account, with no cost barrier to get started$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Deep, native integration with Excel, Teams, and the rest of Microsoft 365$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Simple, intuitive interface that requires little to no onboarding$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Built-in quiz auto-grading makes it well suited for education and training$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Real-time analytics and charts appear automatically as responses come in$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Design and theming options are more limited than dedicated survey or form-builder platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Branching logic and some collaboration features require a Microsoft 365 subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$No native way to collect payments directly through a form$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Advanced research features like quotas or complex logic paths are thinner than specialist tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Feature availability and limits can vary depending on the organization's Microsoft 365 plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Is Microsoft Forms free to use?$q$, $q$Yes. Anyone with a free Microsoft account can create surveys, quizzes, and polls at no cost. Microsoft 365 subscribers get additional features and higher limits.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Do I need a Microsoft 365 subscription to use Forms?$q$, $q$No. A personal Microsoft account is enough to build and share forms. A Microsoft 365 subscription unlocks extras like branching logic and organizational collaboration controls.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Can Microsoft Forms grade quizzes automatically?$q$, $q$Yes. In quiz mode you can mark correct answers and assign point values, and Forms will calculate and display scores automatically.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Does Microsoft Forms work with Excel?$q$, $q$Yes. Responses can be viewed in the built-in results dashboard and exported to Excel with one click for further analysis.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Do people filling out my form need a Microsoft account?$q$, $q$Not necessarily. If you set the form to allow responses from anyone, respondents can fill it out without signing in, depending on your organization's sharing settings.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Classroom quizzes and assessments$q$, $q$Teachers build auto-graded quizzes to test student knowledge and get instant scoring and analytics.$q$, $q$Teachers and educational institutions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Employee feedback and HR surveys$q$, $q$HR teams collect satisfaction surveys, pulse checks, and internal feedback across an organization.$q$, $q$HR teams and internal operations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Event registration and RSVPs$q$, $q$Organizers create simple registration forms to collect attendee details and manage sign-ups for events and meetings.$q$, $q$Event organizers and administrative staff$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Customer and market feedback$q$, $q$Small businesses and product teams gather quick customer opinions or product feedback without a dedicated survey platform.$q$, $q$Small business owners and product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Forms (Free)$q$, $q$$0$q$, $q$Free$q$, $q$["Build surveys, quizzes, and polls","Real-time results dashboard","Basic themes and templates","Share via link or QR code"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Microsoft 365 Personal/Family$q$, $q$Included with subscription$q$, $q$Monthly or annual$q$, $q$["All free-tier form and quiz tools","Personal cloud storage integration","Access across devices"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Microsoft 365 Business/Enterprise$q$, $q$From approximately $6/user/month$q$, $q$Monthly or annual, per user$q$, $q$["Branching logic","Organization-wide sharing and admin controls","Teams and SharePoint integration","Co-authoring for shared forms"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Forms is a free, web-based survey, quiz, and poll builder from Microsoft. Available at forms.microsoft.com, it lets anyone with a Microsoft account create forms directly in a browser without installing software, writing code, or configuring a server. It sits alongside Word, Excel, and PowerPoint as part of the broader Microsoft 365 ecosystem, but it can also be used on its own with a free personal Microsoft account.$q$, $q$The tool covers three core scenarios: gathering feedback through surveys, testing knowledge through auto-graded quizzes, and collecting quick opinions through polls. Forms is especially popular in education, where teachers use its quiz mode to create assessments with instant scoring, and in workplaces, where HR and operations teams use it for employee feedback, event registration, and internal data collection.$q$, $q$Because it is built into Microsoft 365, Forms integrates naturally with Excel for response analysis, Teams for distributing forms and polls inside chats and meetings, and SharePoint for embedding forms into intranet pages. This makes it a convenient default choice for organizations already standardized on Microsoft's productivity suite, even though it is not marketed as a dedicated, standalone survey product the way some competitors are.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$who-microsoft-forms-is-for$q$, $q$Who Microsoft Forms Is For$q$, 2, ARRAY[$q$Microsoft Forms is a strong fit for schools, universities, and individual educators who need a fast way to build quizzes and assessments with automatic grading. Teachers can set correct answers ahead of time, add point values, and let Forms tally scores instantly, saving grading time and giving students quick feedback.$q$, $q$It also suits small businesses, internal HR teams, and departments inside larger organizations that already use Microsoft 365 and want a no-cost way to run employee surveys, satisfaction polls, event RSVPs, or intake forms. Because responses can flow straight into Excel, teams that are already comfortable with spreadsheets can analyze data without learning a separate analytics interface.$q$, $q$Individuals who just need a simple, no-code way to collect structured information, a sign-up sheet, a feedback form for a small event, a quick opinion poll for friends or colleagues, will find Forms approachable. Its clean, minimal interface means new users can build a working form in minutes without a tutorial.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that need highly polished, on-brand survey experiences with extensive visual customization may find Forms limiting. Its theming options are comparatively basic next to dedicated survey and form platforms built around design flexibility, so teams with strong branding requirements may prefer a purpose-built alternative.$q$, $q$Businesses that depend on advanced survey logic, complex piping, multi-path branching across many question types, sophisticated quota management, or advanced statistical analysis built into the tool itself, may outgrow what Forms offers, since many of its more advanced capabilities are gated behind Microsoft 365 licensing and still remain lighter than specialist research tools.$q$, $q$Teams that need to collect payments directly through a form, build deeply customized respondent workflows, or run large-scale market research with panel management should look elsewhere, since Forms is designed as a lightweight, general-purpose data collection tool rather than a full research or commerce platform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Forms offers a drag-and-drop builder supporting multiple question types, choice, text, rating, date, ranking, Likert scales, and file upload, along with a dedicated quiz mode that supports correct-answer marking, point values, and automatic score calculation for respondents.$q$, $q$Collected responses appear in a real-time dashboard with automatically generated charts and summary statistics, and can be exported to Excel with one click for deeper analysis. Forms for Microsoft 365 users also gain branching logic to show or hide questions based on prior answers, shared co-authoring so multiple people can build or review the same form, and organizational controls for who can respond.$q$, $q$Additional features include customizable themes and background images, embedding forms into web pages or SharePoint sites, sharing via QR code or direct link, and native distribution through Microsoft Teams for polls inside chats, channels, and meetings.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$the-microsoft-forms-experience$q$, $q$The Microsoft Forms Experience$q$, 2, ARRAY[$q$Using Microsoft Forms feels deliberately uncomplicated. After signing in with a Microsoft account, users start from a blank form or a template, add questions with a few clicks, and preview exactly how the form will look on desktop or mobile before sharing it.$q$, $q$Sharing is straightforward: a form can be sent as a link, embedded in a webpage, shared via QR code, or posted directly into a Teams channel. Respondents do not need a Microsoft account for public forms, which keeps the experience frictionless for the people filling it out, even if the person building the form does need one.$q$, $q$The overall experience favors speed and simplicity over deep configuration. There is little setup overhead and almost no learning curve, which is precisely why Forms remains a go-to option for quick, low-stakes data collection even among users who also rely on more specialized tools for their heavier survey and research work.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
