INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power Query$q$, $q$Connect to and transform data from hundreds of sources, including databases, cloud services, and spreadsheets, before it enters your model.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$DAX & Data Modeling$q$, $q$Build relationships between tables and write custom calculations and measures using DAX to create a reusable semantic model.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Interactive Reports & Dashboards$q$, $q$Drag-and-drop report design with drill-through, bookmarks, and filtering for exploring data visually.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Natural Language Q&A$q$, $q$Ask questions about your data in plain English and get an automatically generated chart or answer.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$AI Visuals & Copilot$q$, $q$Built-in forecasting, clustering, and key influencer visuals, plus Copilot-assisted report creation and narrative summaries.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Row-Level Security & Governance$q$, $q$Control what each user can see within a shared dataset, and certify or endorse trusted reports across the organization.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Scheduled Refresh & Gateways$q$, $q$Keep cloud reports current with scheduled and incremental refresh, including secure connections to on-premises data via gateways.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Paginated Reports$q$, $q$Create pixel-perfect, printable operational reports for invoices, statements, and other fixed-layout documents.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Mobile Apps$q$, $q$View and interact with dashboards on iOS, Android, and Windows devices while away from a desktop.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power Platform Integration$q$, $q$Embed reports in Teams, SharePoint, and Power Apps, and trigger workflows with Power Automate.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Free Power BI Desktop is fully featured for building and modeling reports, so individuals can start without paying upfront$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Deep integration with Excel, Teams, SharePoint, and Azure lowers friction for organizations already on Microsoft 365$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$DAX and Power Query give advanced users precise control over calculations and data transformation beyond drag-and-drop charting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Enterprise-grade governance, including row-level security, certified datasets, and deployment pipelines, supports large, IT-managed analytics programs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Frequent monthly feature updates from Microsoft keep the platform evolving quickly, including new AI-assisted capabilities$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Licensing can get complex once you factor in Pro, Premium Per User, and capacity-based Premium tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$DAX and proper data modeling have a real learning curve for users expecting simple spreadsheet-style charting$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Desktop is Windows-only, so Mac users need a browser or a virtual machine to author reports$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Sharing and collaboration features require paid licensing, such as Pro or Premium, even for small teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Large or complex data models can hit performance limits without capacity-level Premium licensing or careful optimization$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Is Power BI free?$q$, $q$Power BI Desktop, the report-authoring app, is free to download and use. Sharing reports with others, scheduling refreshes, and collaborating in the Power BI service generally require a paid Pro or Premium license per user.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$What's the difference between Power BI Pro and Premium?$q$, $q$Pro is a per-user license enabling sharing and collaboration. Premium Per User adds larger dataset limits, paginated reports, and more advanced AI features per user. Premium capacity is an organization-wide license providing dedicated compute for larger workloads, priced per capacity rather than per seat.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Does Power BI work on Mac?$q$, $q$Power BI Desktop is a Windows-only application. Mac users typically access reports through the Power BI service in a web browser or run Desktop via a Windows virtual machine.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Can Power BI connect to my existing databases and cloud apps?$q$, $q$Yes, Power BI includes connectors for hundreds of data sources, including SQL Server, Excel, SharePoint, Salesforce, Google Analytics, and various Azure services, plus a data gateway for secure on-premises refresh.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Do I need to know how to code to use Power BI?$q$, $q$Basic report building and drag-and-drop visualizations don't require code, but getting the most out of Power BI, including custom calculations and advanced data modeling, benefits from learning DAX and the Power Query M language.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Executive Sales Dashboards$q$, $q$Sales leaders track pipeline, quota attainment, and regional performance in a live dashboard that refreshes automatically.$q$, $q$Sales and revenue operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Financial Reporting & Close$q$, $q$Finance teams consolidate data from ERP and accounting systems into recurring reports for budget variance, cash flow, and month-end close reviews.$q$, $q$Finance and accounting departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Self-Service Analytics for Excel Users$q$, $q$Analysts who already build pivot tables move into Power BI to create reusable data models and shareable reports without waiting on IT.$q$, $q$Business analysts and department power users$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Enterprise-Wide Governed BI$q$, $q$IT and data teams build a certified, row-level-secured semantic model that feeds dashboards across multiple business units from a single governed source.$q$, $q$Enterprise data and BI teams, IT administrators$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Desktop$q$, $q$Free$q$, $q$N/A$q$, $q$["Full report authoring and data modeling","Power Query and DAX support","Unlimited local reports","No sharing or collaboration included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Pro$q$, $q$$10/user$q$, $q$Monthly per user$q$, $q$["Publish and share reports","Collaborate in workspaces","Scheduled data refresh","Mobile app access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Premium Per User$q$, $q$$20/user$q$, $q$Monthly per user$q$, $q$["Larger dataset and refresh limits","Paginated reports","Advanced AI features","Dataflows"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Premium (Capacity)$q$, $q$From $4,995$q$, $q$Monthly per capacity$q$, $q$["Dedicated compute for the organization","Large-scale distribution to viewers","Paginated reports","Advanced governance and scale"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Power BI is a business intelligence and data visualization platform that lets organizations connect to virtually any data source, transform raw numbers into clean models, and turn them into interactive reports and dashboards. As part of the broader Microsoft Power Platform, it sits alongside Power Apps and Power Automate, sharing connectors, data gateways, and a common Azure Active Directory identity layer that Microsoft-centric organizations already rely on.$q$, $q$At its core, Power BI Desktop is a free authoring tool for building reports using Power Query for data transformation and DAX (Data Analysis Expressions) for calculations. Once a report is built, it's published to the Power BI service, a cloud workspace where reports become shareable dashboards, refresh on a schedule, and can be embedded into apps, SharePoint, or Microsoft Teams.$q$, $q$Licensing follows a per-user and per-capacity model rather than a single flat subscription: individuals and small teams can work for free in Desktop, collaboration and sharing require Power BI Pro, and larger enterprises needing bigger datasets, dedicated compute, or paginated reports typically move to Premium Per User or Premium capacity licensing tied to Power BI's broader Microsoft 365 and Azure ecosystem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$who-microsoft-power-bi-is-for$q$, $q$Who Power BI Is For$q$, 2, ARRAY[$q$Power BI is built for organizations already invested in Microsoft's productivity stack, including Excel, SharePoint, Teams, Azure, and Dynamics 365, who want their BI tool to plug directly into that environment rather than bolt on a separate one. Business analysts, finance teams, and operations managers who already build pivot tables in Excel tend to find Power BI's model-building approach familiar.$q$, $q$It also suits data teams and BI developers who need a governed, enterprise-grade reporting layer. Row-level security, dataset certification, deployment pipelines, and integration with Azure Synapse, Azure Data Lake, and on-premises data gateways make it a credible choice for centralized IT-managed analytics programs, not just self-service dashboards.$q$, $q$Executives and department heads who need recurring, shareable dashboards, such as sales performance, marketing funnels, or financial close status, benefit from Power BI's scheduled refresh and mobile app, letting them check metrics without opening a spreadsheet, while analysts retain a single source of truth for the underlying data model.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams with no existing Microsoft footprint who want a lightweight, dependency-free visualization tool may find Power BI's licensing structure and per-user cost model heavier than they need, especially if the goal is a handful of simple charts rather than a governed enterprise semantic model.$q$, $q$Non-technical users who want to drag in a spreadsheet and get an instant polished chart with zero learning curve may be better served by simpler tools. Power BI's real power comes from data modeling and DAX, which carries a genuine learning curve that can feel like overkill for one-off, disposable reports.$q$, $q$Organizations needing heavy real-time streaming analytics at large scale, deep custom embedding without Microsoft licensing overhead, or a purely open-source or self-hosted BI stack may find Power BI's architecture, refresh-interval model, and capacity-based pricing a mismatch for their technical or budget constraints.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Power BI's feature set spans the full BI lifecycle. Power Query handles data ingestion and transformation from hundreds of connectors, DAX powers custom calculations and measures, and the modeling view lets analysts define relationships across tables to build a reusable semantic model rather than one-off charts.$q$, $q$On the visualization and consumption side, Power BI includes drag-and-drop report building, a library of native and custom visuals, natural-language Q&A for ad hoc questions, and AI-assisted features such as Copilot support for report creation and narrative summaries, plus built-in forecasting, clustering, and key influencer visuals.$q$, $q$For governance and distribution, Power BI offers workspaces, apps for packaging and sharing content, row-level security, dataset certification and endorsement, scheduled and on-premises data refresh via gateways, dataflows for reusable ETL logic, paginated pixel-perfect reports, and mobile apps for iOS, Android, and Windows.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$the-microsoft-power-bi-experience$q$, $q$The Power BI Experience$q$, 2, ARRAY[$q$Day to day, most report authors live in Power BI Desktop, a Windows application where the interface is split between a report canvas, a data and model view for managing relationships, and a formula bar for DAX, closer to an Excel-meets-database tool than a pure design app.$q$, $q$Published reports move to the Power BI service in a browser, where viewers interact with filters, drill-throughs, and bookmarks without needing Desktop installed, and where dashboards can be pinned from multiple reports into a single at-a-glance view, shared via Teams, or embedded in internal portals.$q$, $q$The overall experience rewards investment: initial setup of data models and relationships takes real effort, but once built, refreshing data, adding new visuals, or asking natural-language questions becomes fast, and the tight integration with Excel and Teams means insights end up where Microsoft-centric teams already work.$q$]::text[], 4);
